import{_ as t,o,c as e,ae as r}from"./chunks/framework.BzQXgbNp.js";const n="/assets/dash-5.7qoS3vpn.png",u=JSON.parse('{"title":"🛡️ 領地防護與網頁端權限管理","description":"","frontmatter":{},"headers":[],"relativePath":"Web-Claims-Management.md","filePath":"Web-Claims-Management.md"}'),l={name:"Web-Claims-Management.md"};function i(s,a,d,g,c,h){return o(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="🛡️-領地防護與網頁端權限管理" tabindex="-1">🛡️ 領地防護與網頁端權限管理 <a class="header-anchor" href="#🛡️-領地防護與網頁端權限管理" aria-label="Permalink to &quot;🛡️ 領地防護與網頁端權限管理&quot;">​</a></h1><p>為了防止其他玩家在未經授權的情況下開啟您的箱子或破壞您的建築，本伺服器提供了強大的<strong>領地保護系統</strong>。您可以在遊戲內設定保護區域，並於網頁端進行精細的共建授權。</p><hr><h2 id="🎮-1-遊戲內建立領地流程" tabindex="-1">🎮 1. 遊戲內建立領地流程 <a class="header-anchor" href="#🎮-1-遊戲內建立領地流程" aria-label="Permalink to &quot;🎮 1. 遊戲內建立領地流程&quot;">​</a></h2><h3 id="【第一步】取得工具與框選範圍" tabindex="-1">【第一步】取得工具與框選範圍 <a class="header-anchor" href="#【第一步】取得工具與框選範圍" aria-label="Permalink to &quot;【第一步】取得工具與框選範圍&quot;">​</a></h3><ol><li>合成或取得一支 <strong>木鋤 (Wooden Hoe)</strong> 拿在手上。</li><li>對著想要設定為保護區範圍的<strong>角落 A 方塊按【左鍵】</strong>，聊天欄會顯示：<code>§b[Craft-Core] §f已設定角落 A: X, Y, Z</code>。</li><li>對著另一個對角線的<strong>角落 B 方塊按【右鍵】</strong>，聊天欄會顯示：<code>§b[Craft-Core] §f已設定角落 B: X, Y, Z</code>。</li><li>框選完成後，系統會自動在聊天欄提示該範圍跨越的區塊數量與計費： <ul><li><code>§b[Craft-Core] §f選取區域跨越了 X 個區塊 (Chunk)。總計費用: §e$Y§f 元。</code></li><li><strong>計費規則</strong>：每個區塊（16x16）收費 <strong>$30 遊戲幣</strong>。</li></ul></li></ol><h3 id="【第二步】確認購買領地" tabindex="-1">【第二步】確認購買領地 <a class="header-anchor" href="#【第二步】確認購買領地" aria-label="Permalink to &quot;【第二步】確認購買領地&quot;">​</a></h3><ul><li>在聊天欄輸入指令 <strong><code>/claim</code></strong> 即可扣除您的個人餘額並成功購買該領地。</li><li>購買成功後，該範圍（從基岩到天空頂端）即會建立防護。其他玩家預設將無法在該區域內放置、破壞方塊或開啟容器。</li></ul><hr><h2 id="🖥️-2-網頁端精細好友權限配置" tabindex="-1">🖥️ 2. 網頁端精細好友權限配置 <a class="header-anchor" href="#🖥️-2-網頁端精細好友權限配置" aria-label="Permalink to &quot;🖥️ 2. 網頁端精細好友權限配置&quot;">​</a></h2><p>登入網頁儀表板後，點選 <strong>「領地管理」</strong>，即可在網頁上直觀管理您名下的所有領地：</p><ul><li><strong>領地資訊</strong>：卡片會列出您的領地 ID、座標範圍與所屬世界維度。</li><li><strong>新增好友權限</strong>：在領地卡片中輸入好友的 Minecraft ID，並為其勾選以下核心權限： <ol><li><strong>Build (建造)</strong>：是否允許在領地內放置方塊。</li><li><strong>Break (破壞)</strong>：是否允許在領地內敲除方塊。</li><li><strong>Containers (容器)</strong>：是否允許開啟領地內的箱子、熔爐、木桶等儲存容器。</li><li><strong>Interact (互動)</strong>：是否允許點擊按鈕、踩踏壓力板、拉拉桿或開門。</li></ol></li><li><strong>撤銷授權</strong>：您可以隨時在網頁上一鍵取消勾選，或點選刪除撤銷該好友的所有權限。</li></ul><p><img src="'+n+'" alt="網頁領地權限管理"></p>',13)])])}const _=t(l,[["render",i]]);export{u as __pageData,_ as default};
